WITH ranked(id, dc, puk) AS MATERIALIZED (  SELECT A.Id, A.DateCreated, A.PresentationUniqueKey   FROM MediaItems AS A INDEXED BY idx_dshadow_emby_latest_movies_dcn_puk   WHERE A.Type = 5 AND EXISTS ( SELECT 1 FROM AncestorIds2 AS X WHERE X.ItemId = A.Id AND X.AncestorId IN (100) ) AND NOT EXISTS ( SELECT 1 FROM UserDatas AS U0 WHERE U0.UserDataKeyId = A.UserDataKeyId AND U0.UserId = 42 AND U0.played <> 0 ) AND NOT EXISTS (      SELECT 1       FROM MediaItems AS B INDEXED BY idx_dshadow_emby_latest_movies_puk_dc_cover       WHERE B.Type = 5 AND B.PresentationUniqueKey IS A.PresentationUniqueKey AND ( (B.DateCreated IS NULL AND A.DateCreated IS NOT NULL) OR B.DateCreated < A.DateCreated OR (B.DateCreated IS A.DateCreated AND B.Id < A.Id) ) AND EXISTS ( SELECT 1 FROM AncestorIds2 AS XB WHERE XB.ItemId = B.Id AND XB.AncestorId IN (100) ) AND NOT EXISTS ( SELECT 1 FROM UserDatas AS UB WHERE UB.UserDataKeyId = B.UserDataKeyId AND UB.UserId = 42 AND UB.played <> 0 ) ) ORDER BY (A.DateCreated IS NULL) ASC, A.DateCreated DESC, A.PresentationUniqueKey ASC LIMIT 12 ) SELECT A.Id,A.Name,A.Path,A.ProductionYear,A.RunTimeTicks,A.ParentId,A.Images,UserDatas.IsFavorite,UserDatas.Played,UserDatas.PlaybackPositionTicks,UserDatas.AudioStreamIndex,UserDatas.SubtitleStreamIndex FROM ranked AS R JOIN MediaItems AS A ON A.Id = R.id LEFT JOIN UserDatas ON A.UserDataKeyId = UserDatas.UserDataKeyId AND UserDatas.UserId = 42 ORDER BY (R.dc IS NULL) ASC, R.dc DESC, R.puk ASC LIMIT 12
